 18	import { kialiStyle } from 'styles/StyleUtils';
 19	import { NotificationMessage, NotificationGroup } from '../../types/MessageCenter';
 20	import { MessageCenterActions } from 'actions/MessageCenterActions';
 21	import { AlertDrawerGroup } from './AlertDrawerGroup';
 22	import {
 23	  BoundingClientAwareComponent,
 24	  PropertyType
 25	} from 'components/BoundingClientAwareComponent/BoundingClientAwareComponent';
 26	import { KialiIcon } from 'config/KialiIcon';
 27	
 28	type ReduxProps = {
 29	  expandedGroupId: string | undefined;
 30	  groups: NotificationGroup[];
 31	  isExpanded: boolean;
 32	  isHidden: boolean;
 33	
 34	  expandDrawer: () => void;
 35	  hideDrawer: () => void;
 36	  toggleGroup: (group) => void;
 37	};
 38	
 39	type AlertDrawerProps = ReduxProps & {
 40	  title: string;
 41	};
 42	
 43	const hideGroup = (group: NotificationGroup): boolean => {
 44	  return group.hideIfEmpty && group.messages.length === 0;
 45	};
 46	
 47	const getUnreadCount = (messages: NotificationMessage[]) => {
 48	  return messages.reduce((count, message) => {
 49	    return message.seen ? count : count + 1;
 50	  }, 0);
 51	};
 52	
 53	const getUnreadMessageLabel = (messages: NotificationMessage[]) => {
 54	  const unreadCount = getUnreadCount(messages);
 55	  return unreadCount === 1 ? '1 Unread Message' : `${getUnreadCount(messages)} Unread Messages`;
 56	};
 57	
 58	const noNotificationsMessage = (
 59	  <>
 60	    <InfoIcon />
 61	    No Messages Available
 62	  </>
 63	);
 64	
 65	class AlertDrawerComponent extends React.PureComponent<AlertDrawerProps> {
 66	  static readonly head = kialiStyle({
 67	    paddingBottom: 0
 68	  });
 69	  static readonly body = kialiStyle({
 70	    paddingLeft: 0,
 71	    paddingRight: 0
 72	  });
 73	  static readonly wrapper = kialiStyle({
 74	    overflow: 'auto'
 75	  });
 76	  static readonly wrapperMarginBottom = 10;
 77	  static readonly groups = kialiStyle({
 78	    paddingTop: 0,
 79	    paddingBottom: 0
 80	  });
 81	
 82	  render() {
 83	    const drawer = kialiStyle({
 84	      position: 'absolute',
 85	      right: '0',
 86	      width: this.props.isExpanded ? '80%' : '30em'
 87	    });
 88	
 89	    return (
 90	      !this.props.isHidden && (
 91	        <Card className={drawer} hidden={this.props.isHidden}>
 92	          <CardHeader
 93	            actions={{
 94	              actions: (
 95	                <>
 96	                  {this.props.isExpanded ? (
 97	                    <Button id="alert_drawer_collapse" variant={ButtonVariant.plain} onClick={this.props.expandDrawer}>
 98	                      <KialiIcon.AngleDoubleRight />
 99	                    </Button>
100	                  ) : (
101	                    <Button id="alert_drawer_expand" variant={ButtonVariant.plain} onClick={this.props.expandDrawer}>
102	                      <KialiIcon.AngleDoubleLeft />
103	                    </Button>
104	                  )}
105	                  <Button id="alert_drawer_close" variant={ButtonVariant.plain} onClick={this.props.hideDrawer}>
106	                    <CloseIcon />
107	                  </Button>
108	                </>
109	              ),
110	              hasNoOffset: false,
111	              className: undefined
112	            }}
113	            className={AlertDrawerComponent.head}
114	          >
115	            <CardTitle>{this.props.title}</CardTitle>
116	          </CardHeader>
117	          <CardBody className={AlertDrawerComponent.body}>
118	            {this.props.groups.length === 0 ? (
119	              noNotificationsMessage
120	            ) : (
121	              <BoundingClientAwareComponent
122	                className={AlertDrawerComponent.wrapper}
123	                maxHeight={{
124	                  type: PropertyType.VIEWPORT_HEIGHT_MINUS_TOP,
125	                  margin: AlertDrawerComponent.wrapperMarginBottom
126	                }}
127	              >
128	                <Accordion className={AlertDrawerComponent.groups}>
129	                  {this.props.groups.map(group => {
130	                    return hideGroup(group) ? null : (
131	                      <AccordionItem key={group.id + '_item'}>
132	                        <AccordionToggle
133	                          id={group.id + '_toggle'}
134	                          isExpanded={group.id === this.props.expandedGroupId}
135	                          onClick={() => {
136	                            this.props.toggleGroup(group);
137	                          }}
138	                        >
139	                          {group.title} {getUnreadMessageLabel(group.messages)}
140	                        </AccordionToggle>
141	                        <AccordionContent id={group.id + '_content'} isHidden={group.id !== this.props.expandedGroupId}>
142	                          <AlertDrawerGroup key={group.id} group={group} />
143	                        </AccordionContent>
144	                      </AccordionItem>
145	                    );
146	                  })}
147	                </Accordion>
148	              </BoundingClientAwareComponent>
149	            )}
150	          </CardBody>
151	        </Card>
152	      )
153	    );
154	  }
155	}
156	
157	const mapStateToProps = (state: KialiAppState) => {
158	  return {
159	    expandedGroupId: state.messageCenter.expandedGroupId,
160	    groups: state.messageCenter.groups,
161	    isExpanded: state.messageCenter.expanded,
162	    isHidden: state.messageCenter.hidden
163	  };
164	};
165	
166	const mapDispatchToProps = (dispatch: KialiDispatch) => {
167	  return {
168	    expandDrawer: () => dispatch(MessageCenterActions.toggleExpandedMessageCenter()),
169	    hideDrawer: () => dispatch(MessageCenterActions.hideMessageCenter()),
170	    toggleGroup: group => dispatch(MessageCenterActions.toggleGroup(group.id))
171	  };
172	};
173	
174	export const AlertDrawer = connect(mapStateToProps, mapDispatchToProps)(AlertDrawerComponent);

